def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        if item > capacity:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio == 1:
            priorities[i] = 0
        elif ratio < 0.5:
            priorities[i] = (0.5 - ratio) ** 2 + 0.1
        else:
            log_val = np.log(ratio)
            priorities[i] = abs(log_val) * (1 + (i % 3) * 0.1)
        for j in range(1, 4):
            if i - j >= 0:
                neighbor_capacity = bins[i - j]
                if neighbor_capacity > 0:
                    diff = abs(capacity - neighbor_capacity) / neighbor_capacity
                    priorities[i] += diff * 0.05
            if i + j < len(bins):
                neighbor_capacity = bins[i + j]
                if neighbor_capacity > 0:
                    diff = abs(capacity - neighbor_capacity) / neighbor_capacity
                    priorities[i] += diff * 0.05
    min_priority = np.min(priorities[np.isfinite(priorities)])
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = min_priority * 10
    return priorities
